-- FARM POSITION TAB
local SpotLeft  = Tabs.Spot:AddLeftGroupbox("Переопределение позиции ")
local SpotRight = Tabs.Spot:AddRightGroupbox("Клавиша быстрого сохранения ")

local overrideLabel = SpotLeft:AddLabel({ Text = "Пользовательская позиция: ВЫКЛ " })
local savedCFLabel  = SpotLeft:AddLabel({ Text = "Сохранено: нет " })

SpotLeft:AddButton("Сохранить текущую позицию ", function()
    local char = game.Players.LocalPlayer.Character
    if not char then Library:Notify({Title="Ошибка ", Description="Нет персонажа! ", Duration=3}) return end
    local root = char:FindFirstChild("HumanoidRootPart")
    if not root then Library:Notify({Title="Ошибка ", Description="Нет HumanoidRootPart! ", Duration=3}) return end
    M.setCustomCFrameOverride(root.CFrame)
    local p = root.Position
    savedCFLabel:SetText(string.format("Saved: %.1f, %.1f, %.1f ", p.X, p.Y, p.Z))
    Library:Notify({Title="Позиция сохранена! ", Description=string.format("%.1f, %.1f, %.1f", p.X, p.Y, p.Z), Duration=4})
end)

SpotLeft:AddButton("Сбросить пользовательскую позицию ", function()
    M.setCustomCFrameOverride(nil)
    savedCFLabel:SetText("Сохранено: нет ")
    Library:Notify({Title="Сброшено ", Description="Используется исходная захваченная точка. ", Duration=3})
end)

task.spawn(function()
    while not Library.Unloaded do
        task.wait(0.5)
        overrideLabel:SetText("Custom Position: " .. (M.getCustomCFrameOverride() and "ON " or "OFF "))
    end
end)

local keybindLabel = SpotRight:AddLabel({ Text = "Клавиша быстрого сохранения: F " })

SpotRight:AddButton("Задать клавишу быстрого сохранения ", function()
    M.setSettingKeybind(true)
    keybindLabel:SetText("Нажмите клавишу сейчас... ")
    Library:Notify({Title="Нажмите любую клавишу ", Description="Эта клавиша сохранит вашу точку. ", Duration=4})
end)

SpotRight:AddButton("Очистить клавишу быстрого сохранения", function()
    M.setTeleportKeybind(nil)
    keybindLabel:SetText("Клавиша быстрого сохранения: нет ")
    Library:Notify({Title="Клавиша очищена ", Description="Клавиша быстрого сохранения не задана. ", Duration=3})
end)

M.onKeybindSet = function(keyCode)
    keybindLabel:SetText("Quick-Save Key: " .. keyCode.Name .. " ")
end

M.onSpotSaved = function(p)
    savedCFLabel:SetText(string.format("Saved: %.1f, %.1f, %.1f ", p.X, p.Y, p.Z))
end

